<?php
// Définition d'une classe
class Produit {
    // Propriétés (attributs)
    public string $nom;
    public float  $prix;
    private int   $stock;  // privé : accessible uniquement dans la classe

    // Constructeur : appelé à la création de l'objet
    public function __construct(string $nom, float $prix, int $stock = 0) {
        $this->nom   = $nom;
        $this->prix  = $prix;
        $this->stock = $stock;
    }

    // Méthode
    public function afficher(): string {
        return "{$this->nom} : {$this->prix} EUR (stock: {$this->stock})";  
    }

    // Getter pour propriété privée
    public function getStock(): int {
        return $this->stock;
    }

    // Méthode statique (appartient à la classe, pas à l'instance)
    public static function creerGratuit(string $nom): self {
        return new self($nom, 0.0);
    }
}

// Créer un objet
$clavier = new Produit("Clavier mécanique", 89.99, 15);
echo $clavier->afficher() . "\n";
echo $clavier->nom . "\n";      // public = accessible

// Méthode statique
$gratuit = Produit::creerGratuit("Démo");
echo $gratuit->afficher() . "\n";
?>
```

