<?php
// Classe parente
class Forme {
    protected string $couleur;

    public function __construct(string $couleur = "noir") {
        $this->couleur = $couleur;
    }

    public function getCouleur(): string {
        return $this->couleur;
    }

    // Méthode abstraite : oblige les enfants à l'implémenter
    public function aire(): float {
        return 0.0;
    }
}

// Classe enfant
class Cercle extends Forme {
    private float $rayon;

    public function __construct(float $rayon, string $couleur = "rouge") {
        parent::__construct($couleur);  // appel du constructeur parent
        $this->rayon = $rayon;
    }

    // Surcharge de la méthode parent
    public function aire(): float {
        return M_PI * $this->rayon ** 2;
    }

    public function __toString(): string {
        return "Cercle {$this->couleur} (r={$this->rayon})";  
    }
}

$c = new Cercle(5);
echo $c . "\n";         // utilise __toString
echo round($c->aire(), 2) . "\n";
?>
